{
  "title": "उन्नत खोज विशेषताएँ",
  "group": "खोज क्षमताएँ",
  "options": [
    {
      "text": "ElastiCache",
      "hint": "मुख्य रूप से इन-मेमोरी कैश; नए Valkey संस्करण में खोज विशेषताएँ शामिल हैं।"
    },
    {
      "text": "OpenSearch"
    },
    {
      "text": "Neptune",
      "hint": "ग्राफ़ डेटाबेस जिसमें उन्नत खोज क्षमताएँ हैं"
    },
    {
      "text": "Redshift",
      "hint": "जटिल विश्लेषणात्मक प्रश्न"
    },
    {
      "text": "DocumentDB",
      "hint": "MongoDB-संगत प्रश्न"
    }
  ],
  "questionProse": [
    "यहाँ कौन सी AWS सेवा फुल-टेक्स्ट खोज और खोज विश्लेषण के लिए बनाई गई है?"
  ],
  "explanationProse": [
    "OpenSearch, AWS की प्रबंधित सेवा है जो खोज, लॉग विश्लेषण और फुल-टेक्स्ट खोज कार्यों के लिए है।\n\n      शेष विकल्प उपयोगी सेवाएँ हैं, लेकिन ये सूची में खोज इंजन के रूप में बनाई गई सेवा नहीं हैं:\n      - ElastiCache: मुख्य रूप से इन-मेमोरी कैश। वर्तमान ElastiCache Valkey में अनुक्रमित इन-मेमोरी डेटा के लिए खोज कमांड शामिल हैं, इसलिए अब यह पूरी सेवा के बारे में कहना सटीक नहीं है कि उसमें बिल्ट-इन खोज नहीं है।\n      - Neptune: ग्राफ़ डेटाबेस; यह OpenSearch के साथ फुल-टेक्सट खोज के लिए एकीकृत हो सकता है।\n      - Redshift: SQL विश्लेषण के लिए डेटा वॉच हाउस।\n      - DocumentDB: डॉक्यूमेंट डेटाबेस जिसमें समर्थित संस्करण में MongoDB-संगत खोज है।"
  ]
}
